"use client";

import { useState } from "react";
import { apiMethods } from "@/lib/api-client";

export default function UploadPage() {
  const [fileName, setFileName] = useState("");
  const [dataType, setDataType] = useState("health");
  const [jsonData, setJsonData] = useState("");
  const [message, setMessage] = useState("");

  const handleUpload = async () => {
    try {
      const parsed = JSON.parse(jsonData);

      const res = await apiMethods.uploadData(
        fileName,
        dataType,
        Array.isArray(parsed) ? parsed : [parsed]
      );

      setMessage("✅ Upload successful!");
    } catch (err: any) {
      setMessage("❌ Error: " + err.message);
    }
  };

  return (
    <div className="p-10 text-white">
      <h1 className="text-2xl font-bold mb-6">Upload Dataset</h1>

      <input
        placeholder="File Name"
        className="block mb-4 p-2 text-black"
        value={fileName}
        onChange={(e) => setFileName(e.target.value)}
      />

      <input
        placeholder="Data Type (health)"
        className="block mb-4 p-2 text-black"
        value={dataType}
        onChange={(e) => setDataType(e.target.value)}
      />

      <textarea
        placeholder="Paste JSON data here"
        className="block mb-4 p-2 text-black w-full h-40"
        value={jsonData}
        onChange={(e) => setJsonData(e.target.value)}
      />

      <button
        onClick={handleUpload}
        className="bg-blue-600 px-4 py-2 rounded"
      >
        Upload
      </button>

      <p className="mt-4">{message}</p>
    </div>
  );
}